import { promises as fs } from "node:fs";
import { dirname, relative, resolve, sep } from "node:path";
import { fileURLToPath } from "node:url";

const GENERATED_HEADER = `# Settlex Docs Index

<!-- AUTO-GENERATED by scripts/write-docs-index.mjs. Run \`pnpm docs:index\` after adding or renaming docs. -->

Open the exact doc you need. Each line maps a Markdown path under \`docs/\` to its first top-level heading.

`;

function toPosixPath(path) {
  return path.split(sep).join("/");
}

async function collectMarkdownFiles(rootDir, dir = rootDir) {
  const entries = await fs.readdir(dir, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    const path = resolve(dir, entry.name);

    if (entry.isDirectory()) {
      files.push(...(await collectMarkdownFiles(rootDir, path)));
      continue;
    }

    if (!entry.isFile() || !entry.name.endsWith(".md") || entry.name === "INDEX.md") {
      continue;
    }

    files.push(path);
  }

  return files;
}

async function readTopLevelHeading(filePath) {
  const source = await fs.readFile(filePath, "utf8");
  const heading = source
    .split(/\r?\n/)
    .find((line) => /^#[^#]/.test(line));

  if (!heading) {
    return "No top-level heading";
  }

  return heading.replace(/^#+\s*/, "").replace(/<!--.*?-->/g, "").trim() || "No top-level heading";
}

export async function buildDocsIndex(docsRoot = "docs") {
  const rootDir = resolve(docsRoot);
  const files = await collectMarkdownFiles(rootDir);
  const lines = [];

  for (const filePath of files.sort((a, b) => a.localeCompare(b))) {
    const relPath = toPosixPath(relative(rootDir, filePath));
    const heading = await readTopLevelHeading(filePath);
    lines.push(`${relPath} - ${heading}`);
  }

  return `${GENERATED_HEADER}${lines.join("\n")}\n`;
}

export async function writeDocsIndex(docsRoot = "docs") {
  const rootDir = resolve(docsRoot);
  const outPath = resolve(rootDir, "INDEX.md");
  await fs.mkdir(dirname(outPath), { recursive: true });
  await fs.writeFile(outPath, await buildDocsIndex(rootDir), "utf8");
  return outPath;
}

async function main() {
  const docsRoot = process.argv[2] ?? "docs";
  const outPath = await writeDocsIndex(docsRoot);
  console.log(`Wrote ${toPosixPath(relative(process.cwd(), outPath))}`);
}

const isCli = process.argv[1] && resolve(process.argv[1]) === fileURLToPath(import.meta.url);

if (isCli) {
  main().catch((error) => {
    console.error(error.message);
    process.exit(1);
  });
}
